import sys
import traceback
from typing import Optional, Tuple, List

class BowlingAnalysis:
    """Advanced exception handling and debugging with stack inspection."""

    def __init__(self, bowler_name: str):
        self.bowler_name = bowler_name
        self.deliveries = []
        self.stats = {'runs_conceded': 0, 'wickets': 0, 'balls': 0}

    def analyze_delivery(self, runs: int, is_wicket: bool, 
                        ball_type: str = 'regular') -> dict:
        """Analyze a single delivery with comprehensive error inspection."""
        try:
            # Validate ball_type against allowed values
            allowed_types = ['regular', 'yorker', 'bouncer', 'slower', 'crossseam']
            if ball_type not in allowed_types:
                raise ValueError(f"Unknown ball type: {ball_type}. Allowed: {allowed_types}")

            # Validate runs value
            if runs < 0 or runs > 6:
                raise ValueError(f"Invalid runs value: {runs}. Must be 0-6.")

            # Validate consistency: if wicket, runs should be ≤ 1 typically
            if is_wicket and runs > 1:
                # Log this unusual but valid scenario
                print(f"[DEBUG] Unusual: {runs} runs scored in wicket delivery")

            # Record delivery
            delivery = {
                'bowler': self.bowler_name,
                'runs': runs,
                'is_wicket': is_wicket,
                'ball_type': ball_type
            }
            self.deliveries.append(delivery)

            # Update statistics
            self.stats['runs_conceded'] += runs
            self.stats['wickets'] += int(is_wicket)
            self.stats['balls'] += 1

            return {'success': True, 'delivery': delivery}

        except ValueError as e:
            # Log error with stack context
            exc_type, exc_value, exc_traceback = sys.exc_info()
            print(f"[ERROR] {exc_type.__name__}: {exc_value}")
            print(f"[STACK] Called from:")
            for frame_summary in traceback.extract_tb(exc_traceback):
                print(f"  File '{frame_summary.filename}', line {frame_summary.lineno}")
                print(f"    {frame_summary.line}")
            return {'success': False, 'error': str(e)}

    def calculate_economy(self) -> Optional[float]:
        """Calculate economy rate with defensive checks."""
        try:
            if self.stats['balls'] == 0:
                raise RuntimeError("No deliveries analyzed yet")

            # Economy = runs conceded per 6 balls (per over)
            overs = self.stats['balls'] / 6.0
            economy = self.stats['runs_conceded'] / overs if overs > 0 else 0

            # Sanity check: economy shouldn't exceed 36 (6 sixes per over)
            if economy > 36:
                raise AssertionError(f"Economy {economy} exceeds physical limit")

            return economy

        except (RuntimeError, AssertionError, ZeroDivisionError) as e:
            print(f"[WARNING] Cannot calculate economy: {e}")
            return None

    def get_detailed_stats(self) -> dict:
        """Get statistics with full error context."""
        try:
            total_balls = self.stats['balls']
            assert total_balls > 0, "No deliveries to analyze"

            economy = self.calculate_economy()
            strike_rate = (self.stats['wickets'] / total_balls * 100) if total_balls > 0 else 0

            return {
                'bowler': self.bowler_name,
                'deliveries': total_balls,
                'runs_conceded': self.stats['runs_conceded'],
                'wickets': self.stats['wickets'],
                'economy': economy,
                'strike_rate': f"{strike_rate:.2f}%"
            }

        except AssertionError as e:
            print(f"[ASSERTION FAILED] {e}")
            return None

class InningsSimulation:
    """Simulate innings with exception handling and recovery."""

    def __init__(self, target: int):
        self.target = target
        self.current_score = 0
        self.balls_faced = 0
        self.bowlers: List[BowlingAnalysis] = []

    def add_bowler(self, name: str) -> BowlingAnalysis:
        """Add a bowler to the innings."""
        bowler = BowlingAnalysis(name)
        self.bowlers.append(bowler)
        return bowler

    def execute_delivery(self, bowler_index: int, runs: int, 
                        is_wicket: bool = False) -> Tuple[bool, str]:
        """Execute a delivery with exception handling and context preservation."""
        try:
            if bowler_index < 0 or bowler_index >= len(self.bowlers):
                raise IndexError(f"Bowler index {bowler_index} out of range")

            bowler = self.bowlers[bowler_index]
            result = bowler.analyze_delivery(runs, is_wicket)

            if not result['success']:
                return False, result['error']

            self.current_score += runs
            self.balls_faced += 1

            # Check if target reached
            if self.current_score >= self.target:
                return True, f"Target reached! Score: {self.current_score}/{self.target}"

            remaining = self.target - self.current_score
            return True, f"Score: {self.current_score}/{self.target} (need {remaining})"

        except IndexError as e:
            return False, f"Invalid bowler: {e}"
        except Exception as e:
            print(f"[CRITICAL] Unexpected error: {e}")
            print(traceback.format_exc())
            return False, "Unexpected error occurred"

    def get_match_summary(self) -> dict:
        """Generate match summary with all bowler statistics."""
        try:
            if not self.bowlers:
                raise ValueError("No bowlers recorded")

            bowler_stats = []
            for bowler in self.bowlers:
                stats = bowler.get_detailed_stats()
                if stats:
                    bowler_stats.append(stats)

            return {
                'target': self.target,
                'final_score': self.current_score,
                'balls_faced': self.balls_faced,
                'result': 'Won' if self.current_score >= self.target else 'Lost',
                'bowler_stats': bowler_stats
            }

        except ValueError as e:
            print(f"[ERROR] Cannot generate summary: {e}")
            return {}

# Advanced usage demonstrating exception handling and debugging
def simulate_test_match():
    """Simulate a Test match innings with comprehensive error handling."""
    print("=== Test Match Innings Simulation ===")

    innings = InningsSimulation(target=280)

    # Add bowlers
    bumrah = innings.add_bowler("Jasprit Bumrah")
    siraj = innings.add_bowler("Mohammed Siraj")

    # Simulate deliveries with deliberate errors for debugging
    deliveries = [
        (0, 4, False),   # Bumrah, 4 runs
        (0, 0, False),   # Bumrah, 0 runs (maiden)
        (1, 1, False),   # Siraj, 1 run
        (0, 6, False),   # Bumrah, 6 runs
        (1, 2, False),   # Siraj, 2 runs
        (0, -1, False),  # Invalid: negative runs (will error)
        (0, 3, False),   # Bumrah, 3 runs
        (1, 0, True),    # Siraj, 0 runs, wicket
    ]

    for bowler_idx, runs, is_wicket in deliveries:
        success, message = innings.execute_delivery(bowler_idx, runs, is_wicket)
        print(f"  [{bowler_idx}] {message}")
        if not success:
            print(f"    Recovery: Continuing to next delivery...")

    print("\n=== Match Summary ===")
    summary = innings.get_match_summary()
    for key, value in summary.items():
        if key != 'bowler_stats':
            print(f"{key.upper()}: {value}")

    if summary.get('bowler_stats'):
        print("\n=== Bowler Statistics ===")
        for stats in summary['bowler_stats']:
            print(f"{stats['bowler']}: {stats['deliveries']} balls, "
                  f"{stats['runs_conceded']} runs, {stats['wickets']} wickets")

if __name__ == "__main__":
    simulate_test_match()

from functools import wraps
from typing import TypeVar, Callable, Any
import time

T = TypeVar('T')

class PersistentError(Exception):
    """Exception that persists after retry attempts."""
    def __init__(self, message: str, failures: list):
        self.message = message
        self.failures = failures
        super().__init__(self.message)

def retry(max_attempts: int = 3, delay: float = 0.5):
    """Decorator implementing retry pattern with exponential backoff."""
    def decorator(func: Callable[..., T]) -> Callable[..., T]:
        @wraps(func)
        def wrapper(*args, **kwargs) -> T:
            attempt = 0
            last_exception = None

            while attempt < max_attempts:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    attempt += 1
                    last_exception = e
                    if attempt < max_attempts:
                        wait_time = delay * (2 ** (attempt - 1))  # Exponential backoff
                        print(f"[RETRY] Attempt {attempt} failed: {e}. "
                              f"Retrying in {wait_time:.1f}s...")
                        time.sleep(wait_time)
                    else:
                        print(f"[FAIL] All {max_attempts} attempts failed.")

            raise PersistentError(
                f"Function {func.__name__} failed after {max_attempts} attempts",
                [str(last_exception)]
            ) from last_exception

        return wrapper
    return decorator

def eafp_dictionary_access(player_data: dict, key: str) -> Any:
    """
    EAFP (Easier to Ask for Forgiveness than Permission) pattern:
    Try accessing and handle exception if key doesn't exist.
    """
    try:
        return player_data[key]
    except KeyError:
        print(f"[EAFP] Key '{key}' not found in player data. Using default.")
        return None

def lbyl_dictionary_access(player_data: dict, key: str) -> Any:
    """
    LBYL (Look Before You Leap) pattern:
    Check if key exists before accessing.
    More verbose and less Pythonic.
    """
    if key in player_data:
        return player_data[key]
    else:
        print(f"[LBYL] Key '{key}' not found. Using default.")
        return None

class CricketDataProcessor:
    """Demonstrates custom exceptions and context manager patterns."""

    def __init__(self, data_source: str):
        self.data_source = data_source
        self.is_open = False

    def __enter__(self):
        """Context manager entry: open data source."""
        print(f"[CONTEXT] Opening data source: {self.data_source}")
        self.is_open = True
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        """Context manager exit: close data source and cleanup."""
        print(f"[CONTEXT] Closing data source: {self.data_source}")
        if exc_type is not None:
            print(f"[CONTEXT] Exception occurred: {exc_type.__name__}: {exc_val}")
        self.is_open = False
        return False  # Don't suppress exceptions

    def validate_player_record(self, record: dict) -> None:
        """Validate player record with fail-fast pattern."""
        required_fields = ['name', 'jersey_number', 'role']

        for field in required_fields:
            if field not in record:
                raise ValueError(f"Missing required field: '{field}'")

        # Assertion: jersey number should be positive
        assert record['jersey_number'] > 0, \
            f"Jersey number must be positive, got {record['jersey_number']}"

        # Assertion: role should be valid
        valid_roles = ['batsman', 'bowler', 'all-rounder']
        assert record['role'] in valid_roles, \
            f"Invalid role '{record['role']}'. Valid: {valid_roles}"

    def process_batch(self, records: list) -> dict:
        """Process batch with partial success pattern."""
        results = {'successful': [], 'failed': []}

        for idx, record in enumerate(records):
            try:
                self.validate_player_record(record)
                results['successful'].append(record)
            except (ValueError, AssertionError) as e:
                results['failed'].append({
                    'index': idx,
                    'record': record,
                    'error': str(e)
                })
                print(f"[PARTIAL_FAILURE] Record {idx}: {e}")

        return results

@retry(max_attempts=3, delay=0.2)
def fetch_player_stats(player_name: str) -> dict:
    """Simulated API call with retry decorator."""
    import random
    if random.random() < 0.6:  # 60% chance of failure for demo
        raise ConnectionError(f"Failed to fetch stats for {player_name}")
    return {'name': player_name, 'average': 45.5, 'strike_rate': 95.2}

# Demonstrate all patterns
def demonstrate_patterns():
    print("\n=== EAFP vs LBYL Pattern ===")
    player_data = {'name': 'Virat Kohli', 'jersey': 18, 'avg': 50.5}

    print("EAFP approach:")
    avg = eafp_dictionary_access(player_data, 'avg')
    avg = eafp_dictionary_access(player_data, 'missing_key')

    print("\nLBYL approach:")
    avg = lbyl_dictionary_access(player_data, 'avg')
    avg = lbyl_dictionary_access(player_data, 'missing_key')

    print("\n=== Context Manager Pattern ===")
    try:
        with CricketDataProcessor('players.csv') as processor:
            print(f"Processing data... (is_open={processor.is_open})")
            # Simulate error
            raise ValueError("Corrupted data format")
    except ValueError as e:
        print(f"Caught: {e}")

    print("\n=== Partial Success Pattern ===")
    processor = CricketDataProcessor('players.json')
    processor.is_open = True

    player_records = [
        {'name': 'Rohit Sharma', 'jersey_number': 45, 'role': 'batsman'},
        {'name': 'Jasprit Bumrah', 'jersey_number': 93},  # Missing 'role'
        {'name': 'Virat Kohli', 'jersey_number': 18, 'role': 'invalid_role'},  # Invalid role
        {'name': 'MS Dhoni', 'jersey_number': -7, 'role': 'wicket-keeper'},  # Invalid jersey
    ]

    results = processor.process_batch(player_records)
    print(f"\nProcessed {len(results['successful'])} successful, "
          f"{len(results['failed'])} failed")

    print("\n=== Retry Decorator Pattern ===")
    try:
        stats = fetch_player_stats('Rohit Sharma')
        print(f"Successfully fetched: {stats}")
    except PersistentError as e:
        print(f"All retries failed: {e}")

if __name__ == "__main__":
    demonstrate_patterns()
